                temp_dict = temp_dict.dict[ch]
            else:
                temp = WordDictionary()
                temp_dict.dict[ch] = temp
                temp_dict = temp

        temp_dict.is_word = True

    def search(self, word: str) -> bool:
        temp_dict: WordDictionary = self
        for index, ch in enumerate(word):
            if ch == '.':
                for item in temp_dict.dict.values():
